contracts/access/AccessControl.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/// @title AccessControl - Lapisan Kontrol Akses Berbasis Peran (RBAC) untuk Protokol Bang Bang
/// @notice Mendefinisikan modifier dan peran yang mengatur hak akses semua fungsi protokol.
/// @dev RBAC manual tanpa dependensi OpenZeppelin untuk efisiensi gas maksimal.
///
///      ROLE MAPPING berdasarkan kategori aset:
///        Property → BPN     (Badan Pertanahan Nasional)
///        Vehicle  → Samsat  (Sistem Administrasi Manunggal Satu Atap)
///        Gold     → Pegadaian
///        Other    → Kemenkeu (Kementerian Keuangan)
///
///      Setiap Validator didaftarkan dengan institution tag.
///      Smart contract tidak membatasi verifikasi per institusi (off-chain logic di frontend).

import "../models/AssetSchema.sol";

contract AccessControl {

    // =========================================================
    // STATE VARIABLES — Gas-Optimized Layout
    // =========================================================

    /// @notice Alamat SuperAdmin (Deployer), entitas tertinggi dalam protokol.
    address public owner;

    /// @notice Mapping whitelist: Alamat Validator → status aktif.
    /// @dev O(1) lookup, lebih hemat gas dari array.
    mapping(address => bool) public isVerificator;

    /// @notice Mapping institusi Validator: Alamat → nama institusi (BPN/Samsat/Pegadaian/Kemenkeu).
    /// @dev Disimpan on-chain agar frontend manapun bisa query tanpa state off-chain.
    mapping(address => string) public validatorInstitution;

    // =========================================================
    // EVENTS
    // =========================================================

    /// @notice Dipancarkan saat SuperAdmin menunjuk Validator baru beserta institusinya.
    event VerificatorAppointed(address indexed account, string institution, uint256 timestamp);

    /// @notice Dipancarkan saat SuperAdmin mencabut wewenang Validator.
    event VerificatorRemoved(address indexed account, uint256 timestamp);

    /// @notice Dipancarkan saat kepemilikan kontrak dipindahkan.
    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);

    // =========================================================
    // CONSTRUCTOR
    // =========================================================

    /// @notice Menetapkan deployer sebagai SuperAdmin pertama saat kontrak di-deploy.
    constructor() {
        owner = msg.sender;
        emit OwnershipTransferred(address(0), msg.sender);
    }

    // =========================================================
    // MODIFIERS
    // =========================================================

    /// @notice Membatasi akses hanya untuk SuperAdmin (Owner Kontrak).
    modifier onlyOwner() {
        require(msg.sender == owner, "BangBang: Akses ditolak. Hanya SuperAdmin.");
        _;
    }

    /// @notice Membatasi akses hanya untuk Validator yang telah terdaftar dalam whitelist.
    modifier onlyVerificator() {
        require(isVerificator[msg.sender], "BangBang: Akses ditolak. Bukan Validator resmi.");
        _;
    }

    /// @notice Memberikan akses kepada SuperAdmin DAN Validator.
    modifier onlyAdminOrVerificator() {
        require(
            msg.sender == owner || isVerificator[msg.sender],
            "BangBang: Akses ditolak. Hanya SuperAdmin atau Validator."
        );
        _;
    }

    // =========================================================
    // RBAC ADMIN FUNCTIONS
    // =========================================================

    /// @notice Menunjuk alamat wallet baru sebagai Validator resmi beserta institusinya.
    /// @dev Hanya SuperAdmin. Mencegah penunjukan ulang. institution sebagai calldata hemat gas.
    /// @param _account Alamat wallet calon Validator.
    /// @param _institution Nama institusi: "BPN" | "Samsat" | "Pegadaian" | "Kemenkeu"
    function appointVerificator(address _account, string calldata _institution) external onlyOwner {
        require(_account != address(0), "BangBang: Alamat tidak valid.");
        require(!isVerificator[_account], "BangBang: Alamat sudah terdaftar sebagai Validator.");
        require(bytes(_institution).length > 0, "BangBang: Institusi tidak boleh kosong.");

        isVerificator[_account] = true;
        validatorInstitution[_account] = _institution;

        emit VerificatorAppointed(_account, _institution, block.timestamp);
    }

    /// @notice Mencabut wewenang Validator dari whitelist.
    /// @dev Hanya SuperAdmin. Institution data tetap tersimpan untuk audit history.
    /// @param _account Alamat Validator yang akan dicabut wewenangnya.
    function removeVerificator(address _account) external onlyOwner {
        require(isVerificator[_account], "BangBang: Alamat bukan Validator terdaftar.");
        isVerificator[_account] = false;
        emit VerificatorRemoved(_account, block.timestamp);
    }

    /// @notice Memindahkan kepemilikan SuperAdmin ke alamat baru.
    /// @dev Operasi irreversible jika dikirim ke address salah. Hanya SuperAdmin.
    /// @param _newOwner Alamat pemilik baru.
    function transferOwnership(address _newOwner) external onlyOwner {
        require(_newOwner != address(0), "BangBang: Alamat owner baru tidak valid.");
        emit OwnershipTransferred(owner, _newOwner);
        owner = _newOwner;
    }

    // =========================================================
    // READ FUNCTIONS
    // =========================================================

    /// @notice Mendapatkan institusi validator berdasarkan alamat.
    /// @param _account Alamat validator.
    /// @return Nama institusi (string).
    function getValidatorInstitution(address _account) external view returns (string memory) {
        return validatorInstitution[_account];
    }
}

contracts/BangBang.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./models/AssetSchema.sol";
import "./access/AccessControl.sol";

/// @title BangBang Protocol - Kontrak Utama Manajemen Aset Fisik Terdesentralisasi
/// @author Tim Bang Bang
/// @notice Protokol RWA: pencatatan, verifikasi, dan pengelolaan portofolio aset fisik on-chain.
///
///         ROLE-BASED VALIDATOR (sesuai kategori aset):
///           Property → BPN     | Vehicle → Samsat
///           Gold     → Pegadaian | Other → Kemenkeu
///
///         GAS OPTIMIZATION:
///           - calldata untuk semua string parameter (bukan memory)
///           - unchecked counter increment
///           - swap-and-pop untuk array removal O(1)
///           - escrow zeroed sebelum transfer (CEI pattern, anti-reentrancy)
///           - event indexed fields untuk filter yang efisien
///
/// @dev Mewarisi AccessControl untuk RBAC. Kompatibel dengan Base Sepolia / Ethereum Sepolia Testnet.
contract BangBang is AccessControl {

    // =========================================================
    // STATE VARIABLES
    // =========================================================

    /// @notice Biaya registrasi aset (escrow sampai verifikasi selesai).
    /// @dev Dapat diubah SuperAdmin via setValidationFee(). Tidak retroaktif.
    uint256 public validationFee;

    /// @notice Counter ID aset — auto-increment dari 1.
    /// @dev Private, diakses via getTotalAssets().
    uint256 private _assetCounter;

    /// @notice Mapping utama O(1): ID Aset → Struct Aset.
    mapping(uint256 => Asset) private _assets;

    /// @notice Mapping O(1): Alamat Owner → Daftar ID Aset.
    mapping(address => uint256[]) private _ownerAssets;

    /// @notice Escrow mapping: ID Aset → Jumlah ETH yang ditahan.
    /// @dev Selalu di-zero sebelum transfer untuk mencegah reentrancy.
    mapping(uint256 => uint256) private _escrowBalance;

    // =========================================================
    // EVENTS
    // =========================================================

    /// @notice Asset berhasil didaftarkan. category di-index untuk filter per institusi.
    event AssetRegistered(
        uint256 indexed assetId,
        address indexed owner,
        AssetCategory indexed category,
        uint256 valuation,
        uint256 timestamp
    );

    /// @notice Asset berhasil diverifikasi. Distribusi escrow otomatis: 80/20.
    event AssetVerified(
        uint256 indexed assetId,
        address indexed verificator,
        uint256 feeToVerificator,
        uint256 feeToAdmin,
        uint256 timestamp
    );

    /// @notice Valuasi aset diperbarui oleh pemilik.
    event ValuationUpdated(
        uint256 indexed assetId,
        uint256 oldValuation,
        uint256 newValuation,
        uint256 timestamp
    );

    /// @notice Kepemilikan aset dipindahkan.
    event AssetTransferred(
        uint256 indexed assetId,
        address indexed from,
        address indexed to,
        uint256 timestamp
    );

    /// @notice Asset diarsipkan (soft-delete, data tetap on-chain).
    event AssetArchived(uint256 indexed assetId, address indexed actor, uint256 timestamp);

    /// @notice Biaya validasi diubah SuperAdmin.
    event ValidationFeeUpdated(uint256 oldFee, uint256 newFee, uint256 timestamp);

    // =========================================================
    // CONSTRUCTOR
    // =========================================================

    /// @notice Menginisialisasi protokol dengan biaya validasi awal.
    /// @param _initialFee Biaya validasi awal dalam satuan Wei.
    constructor(uint256 _initialFee) AccessControl() {
        validationFee = _initialFee;
    }

    // =========================================================
    // WRITE FUNCTIONS (CRUD)
    // =========================================================

    /// @notice Mendaftarkan aset fisik baru ke dalam protokol Bang Bang.
    /// @dev Payable — user harus mengirim ETH ≥ validationFee sebagai escrow.
    ///      Menggunakan calldata untuk _name dan _documentHash (hemat gas vs memory).
    ///      Counter increment dengan unchecked (overflow tidak mungkin terjadi dalam praktik).
    /// @param _name         Nama deskriptif aset (e.g., "Villa Dago Pakar").
    /// @param _category     Kategori aset: Property/Vehicle/Gold/Other.
    /// @param _valuation    Nilai taksir aset dalam Wei.
    /// @param _documentHash Hash SHA-256 dari dokumen legal aset (atau IPFS CID).
    /// @return assetId ID unik aset yang baru terdaftar.
    function registerAsset(
        string calldata _name,
        AssetCategory _category,
        uint256 _valuation,
        string calldata _documentHash
    ) external payable returns (uint256 assetId) {
        require(msg.value >= validationFee, "BangBang: Biaya validasi tidak mencukupi.");
        require(bytes(_name).length > 0, "BangBang: Nama aset tidak boleh kosong.");
        require(_valuation > 0, "BangBang: Nilai valuasi harus lebih dari nol.");

        // Gas-efficient counter increment (unchecked: overflow butuh ~10^77 registrasi)
        unchecked { _assetCounter++; }
        assetId = _assetCounter;

        // Simpan escrow sebelum membuat entitas aset
        _escrowBalance[assetId] = msg.value;

        // Buat entitas Asset baru — struct assignment sekali (hemat gas vs field-by-field)
        _assets[assetId] = Asset({
            assetId:      assetId,
            owner:        msg.sender,
            verifiedBy:   address(0),
            valuation:    _valuation,
            registeredAt: block.timestamp,
            verifiedAt:   0,
            category:     _category,
            state:        AssetState.Pending,
            documentHash: _documentHash,
            assetName:    _name
        });

        // Tambahkan ID ke daftar aset owner
        _ownerAssets[msg.sender].push(assetId);

        emit AssetRegistered(assetId, msg.sender, _category, _valuation, block.timestamp);
    }

    /// @notice Memverifikasi aset dan mendistribusikan escrow fee secara otomatis.
    /// @dev Bisa dipanggil langsung oleh Verificator (Self-Service) atau oleh Admin (Relayed).
    /// @param _assetId ID aset yang akan diverifikasi.
    function verifyAsset(uint256 _assetId) external onlyVerificator {
        _processVerification(_assetId, msg.sender);
    }

    /// @notice Memverifikasi aset via Relayer Admin (Verificator tidak butuh MetaMask).
    /// @dev Hanya SuperAdmin. Memungkinkan Verificator menerima fee tanpa bayar gas.
    /// @param _assetId     ID aset.
    /// @param _verificator Alamat dompet Verificator yang akan menerima 80% fee.
    function verifyAssetRelayed(uint256 _assetId, address _verificator) external onlyOwner {
        require(isVerificator[_verificator], "BangBang: Alamat bukan Validator resmi.");
        _processVerification(_assetId, _verificator);
    }

    /// @notice Internal logic untuk distribusi fee 80/20.
    function _processVerification(uint256 _assetId, address _verificator) internal {
        Asset storage asset = _assets[_assetId];
        require(asset.assetId != 0, "BangBang: Aset tidak ditemukan.");
        require(asset.state == AssetState.Pending, "BangBang: Aset bukan dalam status Pending.");

        // EFFECTS
        asset.state      = AssetState.Verified;
        asset.verifiedBy = _verificator;
        asset.verifiedAt = block.timestamp;

        uint256 totalFee = _escrowBalance[_assetId];
        _escrowBalance[_assetId] = 0;

        // INTERACTIONS: 80% to Verificator, 20% to Admin
        uint256 feeToVerificator;
        uint256 feeToAdmin;
        unchecked {
            feeToVerificator = (totalFee * 80) / 100;
            feeToAdmin       = totalFee - feeToVerificator;
        }

        (bool sentToVerificator,) = payable(_verificator).call{value: feeToVerificator}("");
        require(sentToVerificator, "BangBang: Transfer ke Validator gagal.");

        (bool sentToAdmin,) = payable(owner).call{value: feeToAdmin}("");
        require(sentToAdmin, "BangBang: Transfer ke SuperAdmin gagal.");

        emit AssetVerified(_assetId, _verificator, feeToVerificator, feeToAdmin, block.timestamp);
    }

    /// @notice Menolak aset dan mengembalikan escrow fee penuh ke pemilik.
    /// @dev CEI pattern: escrow di-zero SEBELUM refund.
    /// @param _assetId ID aset yang akan ditolak.
    function rejectAsset(uint256 _assetId) external onlyVerificator {
        Asset storage asset = _assets[_assetId];
        require(asset.assetId != 0, "BangBang: Aset tidak ditemukan.");
        require(asset.state == AssetState.Pending, "BangBang: Aset bukan dalam status Pending.");

        // EFFECTS
        asset.state = AssetState.Archived;

        uint256 refundAmount = _escrowBalance[_assetId];
        _escrowBalance[_assetId] = 0; // Zero sebelum transfer

        // INTERACTIONS: Refund ke owner
        if (refundAmount > 0) {
            (bool refunded,) = payable(asset.owner).call{value: refundAmount}("");
            require(refunded, "BangBang: Pengembalian dana ke owner gagal.");
        }

        emit AssetArchived(_assetId, msg.sender, block.timestamp);
    }

    /// @notice Memperbarui nilai taksir aset (hanya owner, aset tidak boleh Archived).
    /// @param _assetId       ID aset yang akan diperbarui.
    /// @param _newValuation  Nilai taksir baru dalam Wei.
    function updateValuation(uint256 _assetId, uint256 _newValuation) external {
        Asset storage asset = _assets[_assetId];
        require(asset.owner == msg.sender, "BangBang: Hanya pemilik aset yang dapat melakukan ini.");
        require(asset.state != AssetState.Archived, "BangBang: Aset telah diarsipkan.");
        require(_newValuation > 0, "BangBang: Nilai valuasi baru harus lebih dari nol.");

        uint256 oldValuation = asset.valuation;
        asset.valuation = _newValuation;

        emit ValuationUpdated(_assetId, oldValuation, _newValuation, block.timestamp);
    }

    /// @notice Memindahkan kepemilikan aset ke alamat lain (hanya Verified).
    /// @dev Menggunakan swap-and-pop O(1) untuk hapus dari owner lama.
    /// @param _to      Alamat penerima aset.
    /// @param _assetId ID aset yang akan ditransfer.
    function transferAsset(address _to, uint256 _assetId) external {
        Asset storage asset = _assets[_assetId];
        require(asset.owner == msg.sender, "BangBang: Hanya pemilik aset yang dapat melakukan ini.");
        require(_to != address(0), "BangBang: Alamat tujuan tidak valid.");
        require(asset.state == AssetState.Verified, "BangBang: Hanya aset terverifikasi yang dapat ditransfer.");

        address previousOwner = asset.owner;
        asset.owner = _to;

        _ownerAssets[_to].push(_assetId);
        _removeFromOwnerList(previousOwner, _assetId);

        emit AssetTransferred(_assetId, previousOwner, _to, block.timestamp);
    }

    /// @notice Mengarsipkan aset (soft-delete, operasi irreversible).
    /// @dev Bisa dipanggil oleh owner aset ATAU SuperAdmin.
    /// @param _assetId ID aset yang akan diarsipkan.
    function archiveAsset(uint256 _assetId) external {
        Asset storage asset = _assets[_assetId];
        require(
            asset.owner == msg.sender || msg.sender == owner,
            "BangBang: Hanya pemilik atau SuperAdmin yang dapat mengarsipkan."
        );
        require(asset.state != AssetState.Archived, "BangBang: Aset sudah diarsipkan.");

        asset.state = AssetState.Archived;

        emit AssetArchived(_assetId, msg.sender, block.timestamp);
    }

    // =========================================================
    // ADMIN FUNCTIONS
    // =========================================================

    /// @notice Mengubah biaya validasi untuk registrasi aset baru.
    /// @dev Hanya SuperAdmin. Tidak berlaku retroaktif.
    /// @param _newFee Biaya validasi baru dalam Wei.
    function setValidationFee(uint256 _newFee) external onlyOwner {
        uint256 oldFee = validationFee;
        validationFee = _newFee;
        emit ValidationFeeUpdated(oldFee, _newFee, block.timestamp);
    }

    /// @notice Fungsi darurat untuk menarik ETH yang tersangkut di kontrak.
    /// @dev Hanya SuperAdmin. Escrow legitimate sudah terdistribusi saat verifyAsset.
    function emergencyWithdraw() external onlyOwner {
        uint256 balance = address(this).balance;
        require(balance > 0, "BangBang: Tidak ada saldo yang perlu ditarik.");
        (bool sent,) = payable(owner).call{value: balance}("");
        require(sent, "BangBang: Penarikan dana darurat gagal.");
    }

    // =========================================================
    // READ FUNCTIONS (VIEW — Gas Free)
    // =========================================================

    /// @notice Mengambil seluruh detail struct aset berdasarkan ID-nya. O(1).
    /// @param _assetId ID aset.
    /// @return Struct Asset lengkap.
    function getAssetDetails(uint256 _assetId) external view returns (Asset memory) {
        require(_assets[_assetId].assetId != 0, "BangBang: Aset tidak ditemukan.");
        return _assets[_assetId];
    }

    /// @notice Mengambil daftar semua ID aset milik sebuah alamat.
    /// @param _owner Alamat wallet yang diperiksa.
    /// @return Array ID aset milik alamat tersebut.
    function getAssetsByOwner(address _owner) external view returns (uint256[] memory) {
        return _ownerAssets[_owner];
    }

    /// @notice Mengembalikan jumlah total aset yang pernah terdaftar.
    /// @return Total aset terdaftar (counter).
    function getTotalAssets() external view returns (uint256) {
        return _assetCounter;
    }

    /// @notice Memeriksa saldo escrow yang ditahan untuk sebuah aset.
    /// @param _assetId ID aset.
    /// @return Jumlah Wei dalam escrow.
    function getEscrowBalance(uint256 _assetId) external view returns (uint256) {
        return _escrowBalance[_assetId];
    }

    /// @notice Mendapatkan institusi validator yang berwenang untuk kategori aset tertentu.
    /// @dev Pure function — tidak membaca state, gas gratis.
    /// @param _category Kategori aset.
    /// @return Nama institusi yang berwenang.
    function getRequiredInstitution(AssetCategory _category) external pure returns (string memory) {
        return getValidatorInstitution(_category);
    }

    // =========================================================
    // INTERNAL HELPER FUNCTIONS
    // =========================================================

    /// @notice Menghapus ID aset dari daftar owner dengan teknik swap-and-pop.
    /// @dev O(1) average — menghindari array shift O(n) yang boros gas.
    ///      unchecked digunakan pada loop counter karena length dari array tidak mungkin overflow uint256.
    /// @param _owner   Alamat owner yang daftarnya diperbarui.
    /// @param _assetId ID aset yang dihapus.
    function _removeFromOwnerList(address _owner, uint256 _assetId) internal {
        uint256[] storage ownerList = _ownerAssets[_owner];
        uint256 length = ownerList.length;
        for (uint256 i = 0; i < length; ) {
            if (ownerList[i] == _assetId) {
                ownerList[i] = ownerList[length - 1]; // Tukar dengan elemen terakhir
                ownerList.pop();                       // Hapus elemen terakhir
                break;
            }
            unchecked { ++i; } // Hemat gas: skip overflow check
        }
    }

    /// @notice Fallback untuk menerima ETH langsung ke kontrak (misal: escrow dari integrasi lain).
    receive() external payable {}
}

contracts/models/AssetSchema.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/// @title AssetSchema - Model Data Aset untuk Protokol Bang Bang
/// @notice Mendefinisikan tipe data utama: Enum, Struct, dan Mapping yang digunakan di seluruh protokol.
/// @dev File ini adalah lapisan "Model" dalam arsitektur MVC. Tidak berisi logika bisnis.
///      Dioptimalkan untuk storage packing: tipe kecil dikelompokkan bersama untuk hemat gas.

/// @notice Kategori jenis aset fisik yang didukung oleh protokol.
/// @dev Role-based validator mapping:
///      Property → BPN (Badan Pertanahan Nasional)
///      Vehicle  → Samsat
///      Gold     → Pegadaian
///      Other    → Kemenkeu (Kementerian Keuangan)
enum AssetCategory {
    Property,   // Properti & Tanah (SHM, HGB) → Validator: BPN
    Vehicle,    // Kendaraan Bermotor (BPKB)    → Validator: Samsat
    Gold,       // Logam Mulia (Antam, LM)      → Validator: Pegadaian
    Other       // Properti lain, dll            → Validator: Kemenkeu
}

/// @notice Institusi validator berdasarkan kategori aset.
/// @dev Digunakan sebagai identifier role di frontend untuk filtering validator sesuai wewenang.
enum ValidatorInstitution {
    BPN,        // Badan Pertanahan Nasional (untuk Property/Tanah)
    Samsat,     // Sistem Administrasi Manunggal Satu Atap (untuk Kendaraan)
    Pegadaian,  // PT Pegadaian (untuk Emas/Logam Mulia)
    Kemenkeu    // Kementerian Keuangan (untuk aset lainnya)
}

/// @notice Status lifecycle aset dalam sistem.
enum AssetState {
    Pending,    // Baru didaftarkan, menunggu verifikasi
    Verified,   // Telah diverifikasi oleh Validator yang sah
    Archived    // Aset dinonaktifkan (immutable blockchain)
}

/// @notice Struktur data utama yang merepresentasikan satu unit aset fisik on-chain.
/// @dev Gas-optimized storage packing:
///      - bool (1 byte) digabung dengan enum (1 byte) di slot yang sama
///      - address (20 bytes) diletakkan terpisah karena tidak bisa dipacking dengan uint256
///      - String disimpan terakhir karena dynamic type (tidak mempengaruhi packing slot fixed)
struct Asset {
    // === Slot 1: assetId (32 bytes — 1 slot penuh) ===
    uint256 assetId;

    // === Slot 2: owner (20 bytes) + 12 bytes sisa → tidak cukup untuk uint96/address lain ===
    address owner;

    // === Slot 3: verifiedBy (20 bytes) ===
    address verifiedBy;

    // === Slot 4: valuation (32 bytes — 1 slot penuh) ===
    uint256 valuation;

    // === Slot 5: registeredAt (32 bytes — 1 slot penuh) ===
    uint256 registeredAt;

    // === Slot 6: verifiedAt (32 bytes — 1 slot penuh) ===
    uint256 verifiedAt;

    // === Slot 7: category (1 byte) + state (1 byte) = 2 bytes total, packed dalam 1 slot ===
    AssetCategory category;
    AssetState    state;

    // === Dynamic slots: string (stored as dynamic arrays, tidak mempengaruhi packing di atas) ===
    string documentHash;  // SHA-256 hash dokumen legal (BPKB, SHM, dll)
    string assetName;     // Nama deskriptif aset
}

/// @notice Helper function membaca institusi validator yang berwenang berdasarkan kategori aset.
/// @dev Pure function — tidak membaca state, hemat gas sebagai lookup table.
/// @param category Kategori aset yang ingin dicek.
/// @return Nama institusi validator dalam bentuk string.
function getValidatorInstitution(AssetCategory category) pure returns (string memory) {
    if (category == AssetCategory.Property) return "BPN";
    if (category == AssetCategory.Vehicle)  return "Samsat";
    if (category == AssetCategory.Gold)     return "Pegadaian";
    return "Kemenkeu";
}

